// Get LM Studio response
const raw = $json.choices[0].message.content;

// Parse the JSON string into an object
let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error("Failed to parse LM Studio JSON: " + error.message);
}

// Return clean object for FastAPI
return [
  {
    json: parsed
  }
];
